    cudaMalloc(&knodesD, knodes_mem);
    checkCUDAError("cudaMalloc knodesD");

    long *currKnodeD;
    cudaMalloc(&currKnodeD, count*sizeof(long));
    checkCUDAError("cudaMalloc currKnodeD");

    long *offsetD;
    cudaMalloc(&offsetD, count*sizeof(long));
    checkCUDAError("cudaMalloc offsetD");

    int *keysD;
    cudaMalloc(&keysD, count*sizeof(int));
    checkCUDAError("cudaMalloc keysD");

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    record *ansD;
